int findMinimumSumDifference(vector<int>& inputNumbers) {
    int n = inputNumbers.size() / 2;
    map<int, set<int>> leftSums, rightSums;
    for (int mask = 0; mask < (1 << n); mask++) {
        int sum = 0;
        int count = 0;
        for (int i = 0; i < n; i++) {
            if (mask & (1 << i)) {
                sum += inputNumbers[i];
                count++;
            } else {
                sum -= inputNumbers[i];
            }
        }
        leftSums[count].insert(sum);
    }
    for (int mask = 0; mask < (1 << n); mask++) {
        int sum = 0;
        int count = 0;
        for (int i = 0; i < n; i++) {
            if (mask & (1 << i)) {
                sum += inputNumbers[n + i];
                count++;
            } else {
                sum -= inputNumbers[n + i];
            }
        }
        rightSums[count].insert(sum);
    }
    int minDiff = INT_MAX;
    for (int leftCount = 0; leftCount <= n; leftCount++) {
        int rightCount = n - leftCount;
        vector<int> leftList(leftSums[leftCount].begin(), leftSums[leftCount].end());
        vector<int> rightList(rightSums[rightCount].begin(), rightSums[rightCount].end());
        for (int leftVal : leftList) {
            int target = -leftVal;
            auto it = lower_bound(rightList.begin(), rightList.end(), target);
            if (it != rightList.end()) {
                minDiff = min(minDiff, abs(leftVal + *it));
            }
            if (it != rightList.begin()) {
                --it;
                minDiff = min(minDiff, abs(leftVal + *it));
            }
        }
    }
    return minDiff;
}

