function findMinimumSumDifference(inputNumbers) {
    const n = inputNumbers.length / 2;
    const left = inputNumbers.slice(0, n);
    const right = inputNumbers.slice(n);
    const sumTotal = inputNumbers.reduce((a, b) => a + b, 0);
    const getSumsByCount = (arr) => {
        const map = Array.from({ length: arr.length + 1 }, () => []);
        const dfs = (i, count, sum) => {
            if (i === arr.length) {
                map[count].push(sum);
                return;
            }
            dfs(i + 1, count + 1, sum + arr[i]);
            dfs(i + 1, count, sum);
        };
        dfs(0, 0, 0);
        return map;
    };
    const leftSums = getSumsByCount(left);
    const rightSums = getSumsByCount(right);
    for (let i = 0; i <= n; i++) {
        rightSums[i].sort((a, b) => a - b);
    }
    let res = Infinity;
    for (let i = 0; i <= n; i++) {
        const leftArr = leftSums[i];
        const rightArr = rightSums[n - i];
        for (const lSum of leftArr) {
            const target = sumTotal / 2 - lSum;
            let low = 0, high = rightArr.length - 1;
            while (low < high) {
                const mid = (low + high) >>> 1;
                if (rightArr[mid] < target) low = mid + 1;
                else high = mid;
            }
            for (const idx of [low, low - 1]) {
                if (idx >= 0 && idx < rightArr.length) {
                    const curSum = lSum + rightArr[idx];
                    const curDiff = Math.abs(sumTotal - 2 * curSum);
                    if (curDiff < res) res = curDiff;
                }
            }
        }
    }
    return res;
}
